const gradeContext = {
  'HG':   '🟢 High Grade — Best starter kit. Build time: 1-2 hrs.',
  'RG':   '🔵 Real Grade — HG detail at MG price. Panel lines heaven.',
  'MG':   '🟡 Master Grade — Inner frame, serious detail. 4-8 hrs.',
  'PG':   '🔴 Perfect Grade — Full mechanical detail. 20+ hrs.',
  'MGSD': '⭐ MGSD — Super Deformed with MG-level engineering. Unique.',
  'MGEX': '🔴 MG Extreme — LED, chrome, top-tier. Grail kit.',
};
const gradeKey = Object.keys(gradeContext).find(k =>
  title.toUpperCase().includes(k) || (tags.join(' ').toUpperCase().includes(k))
);
const beginnerLine = gradeContext[gradeKey] ?? '';

// FOMO trigger (Tier 1 only — ngeekhong never overhyped Tier 3)
const isTier1 = score >= 9 || tier === 'urgent';
const fomoLine = isTier1
  ? `\n🚨 P-Bandai / Limited window — order fast or pay scalper price.`
  : '';

// Affiliate link (HLJ default, swap for Shopee/GTO per source)
const affiliateBase = 'https://hlj.com/?ref=mechahub';
const affiliateLink = `\n🛒 Check availability: ${affiliateBase}`;

// Source credibility line (ngeekhong always cited primary)
const sourceMap = {
  'gunjap':      '📰 Source: GUNJAP.net (JP primary)',
  'gundam.info': '📰 Source: Gundam.info (Official)',
  'reddit':      '📰 Source: r/Gunpla community',
  'bandai':      '📰 Source: Bandai Hobby Site (Official)',
  'hobbyplanet': '📰 Source: Hobby Planet PH',
};
const sourceLine = sourceMap[source.toLowerCase()] ?? `📰 Source: ${source}`;

// Build the post
const phpLine = phpPrice
  ? `💰 Est. PHP: ₱${phpPrice} (¥${yenPrice?.toLocaleString()} at today's rate)`
  : '';

const postCopy =
`${isTier1 ? '🔥' : '📢'} ${title}

${content}
${phpLine ? '\n' + phpLine : ''}
${beginnerLine ? '\n' + beginnerLine : ''}
${fomoLine}
${affiliateLink}

${sourceLine}
#Gunpla #MechaHub ${tags.map(t => '#' + t.replace(/\s+/g, '')).join(' ')}`.trim();

return [{
  json: {
