// Dedup by SKU — keep the most recently scraped occurrence
const map = new Map();

for (const item of $input.all()) {
  const sku = item.json.sku;
  const existing = map.get(sku);

  if (!existing || new Date(item.json.scraped_at) > new Date(existing.json.scraped_at)) {
    map.set(sku, item);
  }
}

return Array.from(map.values());

return items.map(item => {
  // SUCCESS: FB returns { id: '...', post_supports_client_mutation_id: true }
  const isSuccess =
    typeof item.json?.id === 'string' &&
    item.json.id.length > 0;

  // NO INTERNET: axios ENOTFOUND / network error
  const isNetworkError =
    item.json?.isAxiosError === true ||
    item.json?.code === 'ENOTFOUND' ||
    item.json?.name === 'Error';

  // API ERROR: FB returned a 4xx with headers
  const isApiError =
    item.json?.statusCode === 400 ||
    item.json?.statusCode === 403 ||
    item.json?.statusCode === 500;

  const isBadRequest = !isSuccess; // anything that is not a clean FB id response

  return {
    json: {
      statusCode:   item.json?.statusCode ?? null,
      isBadRequest,
      isNetworkError,
      isApiError,
      fb_post_id:   isSuccess ? item.json.id : null,
      authHeader:   item.json?.headers?.['www-authenticate'] ?? '',
      debugLink:    item.json?.headers?.['debug-link'] ?? '',
      errorMid:     item.json?.headers?.['error-mid'] ?? '',
      errorCode:    item.json?.code ?? null,
      errorName:    item.json?.name ?? null,
    }
  };
});

