// n8n Code Node: Transform image_url → images array for Supabase
// SOURCE OF TRUTH: scraper image_url only — no fabricated URLs
// Handles: single string, comma-separated, or already an array

return $input.all().map(item => {
  const data = item.json;
  const rawImage = data.image_urls;

  if (!rawImage) {
    return { json: { ...data, images: [], image_count: 0 } };
  }

  // Normalize to array — loop through whatever scraper actually provides
  let imagesArray = [];

  if (Array.isArray(rawImage)) {
    // Already an array from scraper
    imagesArray = rawImage.filter(Boolean);
  } else if (typeof rawImage === 'string' && rawImage.includes(',')) {
    // Comma-separated multiple URLs: "https://..., https://..."
    imagesArray = rawImage.split(',').map(u => u.trim()).filter(Boolean);
  } else if (typeof rawImage === 'string') {
    // Single URL — wrap as-is, no modification
    imagesArray = [rawImage];
  }

  return {
    json: {
      ...data,
      images: imagesArray,       // Supabase JSONB array field
      image_count: imagesArray.length
    }
  };
});

const item = $('Loop Over Items').first().json;

const bitly    = $('get bit ly').first()?.json?.link || '';
const tinyurl  = $('get tiny url').first()?.json?.data || '';
const affiliate = item.affiliate_url;
const link     = bitly || tinyurl || affiliate;

const symbolMap = {
  jpy: '¥',
  php: '₱',
  sgd: 'S$',
  usd: '$',
  myr: 'RM',
  thb: '฿',
  idr: 'Rp'
};

const priceLines = Object.keys(item)
  .filter(k => k.startsWith('price_'))
  .map(k => {
    const currency = k.split('_').pop();
    const symbol = symbolMap[currency] || '';
    let value = item[k];
    if (currency === 'jpy' && typeof value === 'string') {
      value = value.replace(/[^0-9.]/g, '');
    }
    if (currency === 'idr') value = Number(value).toLocaleString();
    return `${symbol}${value}`;
  })
  .join(' · ');

// Stock
const stock = item.stock;
const stockNum = parseInt((stock || '').match(/\d+/)?.[0] || '0');
const urgency = stockNum === 1
  ? '1 left'
  : `${stockNum} left`;

// Drop grade_scale if Unknown
const grade = item.grade_scale && item.grade_scale !== 'Unknown'
  ? ` (${item.grade_scale})` : '';

const message = `${item.name}${grade}\n${priceLines}\n${urgency} · ${link}`;

return $input.all().map(i => ({
  json: { ...i.json, message, link }
}));
